// src/services/api.js
const API_URL = 'http://localhost:5000/api';

// Helper function for API calls
async function fetchAPI(endpoint, options = {}) {
  const response = await fetch(`${API_URL}${endpoint}`, {
    headers: {
      'Content-Type': 'application/json',
      ...options.headers,
    },
    ...options,
  });

  if (!response.ok) {
    throw new Error(`API Error: ${response.status}`);
  }

  return response.json();
}

// Health check
export const checkHealth = async () => {
  return fetchAPI('/health');
};

// Get all courses
export const getCourses = async () => {
  return fetchAPI('/courses');
};

// Get featured courses (first 6)
export const getFeaturedCourses = async (limit = 6) => {
  const data = await getCourses();
  return {
    courses: data.courses.slice(0, limit),
    total: data.courses.length
  };
};

// Get notes
export const getNotes = async () => {
  return fetchAPI('/notes');
};

// Add sample courses
export const addSampleCourses = async () => {
  return fetchAPI('/add-sample-courses', { method: 'POST' });
};

// Get database info
export const getDBInfo = async () => {
  return fetchAPI('/db-info');
};

// Get stats (mock for now, will update when backend has stats endpoint)
export const getStats = async () => {
  try {
    const dbInfo = await getDBInfo();
    return {
      totalNotes: dbInfo.tables.notes || 0,
      totalPYQs: 0, // Will update when we have separate PYQ tracking
      totalCourses: dbInfo.tables.courses || 0,
      totalDownloads: dbInfo.tables.notes ? dbInfo.tables.notes * 10 : 0 // Mock calculation
    };
  } catch (error) {
    // Fallback to mock stats
    return {
      totalNotes: 500,
      totalPYQs: 1000,
      totalCourses: 50,
      totalDownloads: 2000
    };
  }
};

export default {
  checkHealth,
  getCourses,
  getFeaturedCourses,
  getNotes,
  addSampleCourses,
  getDBInfo,
  getStats
};
